#!/usr/bin/env bash
set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
SKILLS_LIB_DIR="$(cd "$SCRIPT_DIR/../../lib" && pwd)"
# shellcheck source=../../lib/socialpredict_backend_common.sh
source "$SKILLS_LIB_DIR/socialpredict_backend_common.sh"

REPO_DIR="$(resolve_target_repo_dir "${1:-}")"
BACKEND_DIR="$(require_backend_dir "$REPO_DIR")"
BACKEND_DIR="$(cd "$BACKEND_DIR" && pwd)"
SPEC_PATH="$BACKEND_DIR/docs/openapi.yaml"

if [ ! -f "$SPEC_PATH" ]; then
  echo "Expected OpenAPI spec at $SPEC_PATH" >&2
  exit 1
fi

if [ ! -f "$BACKEND_DIR/go.mod" ]; then
  echo "Expected Go module at $BACKEND_DIR/go.mod" >&2
  exit 1
fi

TMP_ROOT="${TMPDIR:-/tmp}/socialpredict-kin-conformance"
mkdir -p "$TMP_ROOT"

GO_CACHE_DIR="$TMP_ROOT/gocache"
GO_MOD_CACHE_DIR="$TMP_ROOT/gomodcache"
mkdir -p "$GO_CACHE_DIR" "$GO_MOD_CACHE_DIR"

TMP_GO="$(mktemp "$TMP_ROOT/kin-conformance-XXXX.go")"
cleanup() {
  rm -f "$TMP_GO"
}
trap cleanup EXIT

cat >"$TMP_GO" <<'EOF'
package main

import (
	"context"
	"fmt"
	"os"
	"sort"
	"strings"

	"github.com/getkin/kin-openapi/openapi3"
)

func fail(format string, args ...any) {
	fmt.Fprintf(os.Stderr, format+"\n", args...)
	os.Exit(1)
}

func main() {
	if len(os.Args) != 2 {
		fail("usage: kin-conformance <spec-path>")
	}

	ctx := context.Background()
	loader := &openapi3.Loader{IsExternalRefsAllowed: true}
	doc, err := loader.LoadFromFile(os.Args[1])
	if err != nil {
		fail("load OpenAPI document: %v", err)
	}
	if err := doc.Validate(ctx); err != nil {
		fail("validate OpenAPI document: %v", err)
	}

	var problems []string
	operationCount := 0

	for path, pathItem := range doc.Paths.Map() {
		for method, operation := range pathItem.Operations() {
			operationCount++
			label := strings.ToUpper(method) + " " + path
			if operation.OperationID == "" {
				problems = append(problems, label+": missing operationId")
			}
			if operation.Responses == nil || operation.Responses.Len() == 0 {
				problems = append(problems, label+": missing responses")
				continue
			}
			for status, responseRef := range operation.Responses.Map() {
				if responseRef == nil || responseRef.Value == nil {
					problems = append(problems, label+": nil response for status "+status)
					continue
				}
				for mediaType, mediaRef := range responseRef.Value.Content {
					if mediaRef == nil {
						problems = append(problems, label+": nil media type "+mediaType+" for status "+status)
						continue
					}
					if mediaRef.Schema != nil && mediaRef.Schema.Value == nil && mediaRef.Schema.Ref == "" {
						problems = append(problems, label+": empty schema for "+status+" "+mediaType)
					}
				}
			}
		}
	}

	if len(problems) > 0 {
		sort.Strings(problems)
		for _, problem := range problems {
			fmt.Fprintln(os.Stderr, problem)
		}
		fail("kin-openapi conformance found %d issue(s)", len(problems))
	}

	fmt.Printf("PASS: kin-openapi loaded and validated %d operation(s)\n", operationCount)
}
EOF

echo "[1/2] Run existing backend OpenAPI validation test"
(
  cd "$BACKEND_DIR"
  GOCACHE="$GO_CACHE_DIR" GOMODCACHE="$GO_MOD_CACHE_DIR" go test ./... -run TestOpenAPISpecValidates -count=1
)

echo "[2/2] Run kin-openapi operation conformance checks"
(
  cd "$BACKEND_DIR"
  GOCACHE="$GO_CACHE_DIR" GOMODCACHE="$GO_MOD_CACHE_DIR" go run "$TMP_GO" "$SPEC_PATH"
)

package handlers

import (
	"encoding/json"
	"net/http"
	"strings"
)

type FailureReason string

const (
	ReasonMethodNotAllowed       FailureReason = "METHOD_NOT_ALLOWED"
	ReasonInvalidRequest         FailureReason = "INVALID_REQUEST"
	ReasonInvalidToken           FailureReason = "INVALID_TOKEN"
	ReasonAuthorizationDenied    FailureReason = "AUTHORIZATION_DENIED"
	ReasonPasswordChangeRequired FailureReason = "PASSWORD_CHANGE_REQUIRED"
	ReasonNotFound               FailureReason = "NOT_FOUND"
	ReasonUserNotFound           FailureReason = "USER_NOT_FOUND"
	ReasonMarketNotFound         FailureReason = "MARKET_NOT_FOUND"

	ReasonValidationFailed    FailureReason = "VALIDATION_FAILED"
	ReasonMarketClosed        FailureReason = "MARKET_CLOSED"
	ReasonInsufficientBalance FailureReason = "INSUFFICIENT_BALANCE"
	ReasonNoPosition          FailureReason = "NO_POSITION"
	ReasonInsufficientShares  FailureReason = "INSUFFICIENT_SHARES"
	ReasonDustCapExceeded     FailureReason = "DUST_CAP_EXCEEDED"
	ReasonInternalError       FailureReason = "INTERNAL_ERROR"
)

var publicFailureReasons = []FailureReason{
	ReasonMethodNotAllowed,
	ReasonInvalidRequest,
	ReasonInvalidToken,
	ReasonAuthorizationDenied,
	ReasonPasswordChangeRequired,
	ReasonNotFound,
	ReasonUserNotFound,
	ReasonMarketNotFound,
	ReasonValidationFailed,
	ReasonMarketClosed,
	ReasonInsufficientBalance,
	ReasonNoPosition,
	ReasonInsufficientShares,
	ReasonDustCapExceeded,
	ReasonInternalError,
}

// PublicFailureReasons returns the shared public reason vocabulary for the
// touched API envelope routes.
func PublicFailureReasons() []FailureReason {
	return append([]FailureReason(nil), publicFailureReasons...)
}

type SuccessEnvelope[T any] struct {
	OK     bool `json:"ok"`
	Result T    `json:"result"`
}

type FailureEnvelope struct {
	OK     bool   `json:"ok"`
	Reason string `json:"reason"`
}

func WriteResult[T any](w http.ResponseWriter, statusCode int, result T) error {
	return writeJSON(w, statusCode, SuccessEnvelope[T]{
		OK:     true,
		Result: result,
	})
}

func WriteFailure(w http.ResponseWriter, statusCode int, reason FailureReason) error {
	return writeJSON(w, statusCode, FailureEnvelope{
		OK:     false,
		Reason: string(reason),
	})
}

func WriteBusinessFailure(w http.ResponseWriter, reason FailureReason) error {
	return WriteFailure(w, http.StatusOK, reason)
}

// AuthFailureReason maps auth-layer HTTP outcomes to the shared public reason
// vocabulary used by touched envelope handlers.
func AuthFailureReason(statusCode int, message string) FailureReason {
	switch {
	case statusCode >= http.StatusInternalServerError:
		return ReasonInternalError
	case statusCode == http.StatusUnauthorized:
		return ReasonInvalidToken
	case statusCode == http.StatusForbidden && strings.EqualFold(message, "Password change required"):
		return ReasonPasswordChangeRequired
	case statusCode == http.StatusForbidden:
		return ReasonAuthorizationDenied
	case statusCode == http.StatusNotFound:
		return ReasonUserNotFound
	case statusCode == http.StatusBadRequest:
		return ReasonValidationFailed
	default:
		return ReasonInternalError
	}
}

func IsValidationMessage(message string) bool {
	lower := strings.ToLower(message)
	return strings.Contains(lower, "invalid") ||
		strings.Contains(lower, "exceeds") ||
		strings.Contains(lower, "must") ||
		strings.Contains(lower, "cannot") ||
		strings.Contains(lower, "required")
}

func writeJSON(w http.ResponseWriter, statusCode int, payload any) error {
	body, err := json.Marshal(payload)
	if err != nil {
		return err
	}

	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(statusCode)
	_, err = w.Write(append(body, '\n'))
	return err
}

